// 图片居中对齐，表格等宽且跨页重复表头，公式居中、编号右对齐
var doc = Application.ActiveDocument;
var range = doc.Range();
range.SelectAll();

// 1. 图片居中对齐
for (var i = 0; i < doc.Shapes.Count; i++) {
    var shape = doc.Shapes.Item(i);
    try {
        shape.LockAspectRatio = false;
        shape.Left = (doc.PageSetup.PageWidth - shape.Width) / 2;
        // 垂直方向不强制居中，保持原有位置
    } catch (e) {}
}

// 2. 表格：等宽 + 跨页重复表头
for (var j = 0; j < doc.Tables.Count; j++) {
    var table = doc.Tables.Item(j);
    try {
        // 表格宽度与页面等宽（减去左右页边距）
        var pageWidth = doc.PageSetup.PageWidth;
        var leftMargin = doc.PageSetup.LeftMargin;
        var rightMargin = doc.PageSetup.RightMargin;
        table.PreferredWidthType = 1; // wdPreferredWidthPercentage
        table.PreferredWidth = pageWidth - leftMargin - rightMargin;

        // 跨页时重复表头（假设第一行为表头）
        if (table.Rows.Count > 1) {
            table.AllowAutoFit = true;
            // 设置第一行在跨页时重复
            table.Rows.First.AllowBreakAcrossPages = false;
            // WPS JS API 中设置重复标题行的方式
            try {
                table.Rows.First.Range.Paragraphs.Item(1).TextWrap = 0; // wdWrapNone
            } catch(e) {}
        }
    } catch (e) {}
}

// 3. 公式处理：公式居中，编号右对齐
// 遍历段落，查找包含公式的段落（通常公式段以"("开头或包含特殊字符）
var paras = doc.Paragraphs;
for (var k = 0; k < paras.Count; k++) {
    var para = paras.Item(k);
    var text = para.Range.Text.trim();
    // 简单判断：如果段落以"("开头且包含")"，可能是公式编号段
    if (text.indexOf("(") === 0 && text.indexOf(")") > 0) {
        try {
            para.Range.ParagraphFormat.Alignment = 2; // 右对齐（公式编号）
        } catch (e) {}
    } else if (text.match(/^[^()]*$/)) {
        // 可能为纯公式段落（无编号），居中
        try {
            para.Range.ParagraphFormat.Alignment = 1; // 居中
        } catch (e) {}
    }
}

return {
    success: true,
    message: "图片已居中，表格已设为等宽并启用跨页重复表头，公式及编号已按规则对齐。"
};

// 图片居中对齐，表格等宽且跨页重复表头，公式居中、编号右对齐
var doc = Application.ActiveDocument;

