for (var i = 0; i < shapes.Count; i++) {
    var shape = shapes.Item(i);
    try {
        var pageWidth = doc.PageSetup.PageWidth;
        shape.Left = (pageWidth - shape.Width) / 2;
    } catch (e) {}
}

// 2. 表格：等宽 + 跨页重复表头
var tables = doc.Tables;
for (var j = 0; j < tables.Count; j++) {
    var table = tables.Item(j);
    try {
        var pageWidth = doc.PageSetup.PageWidth;
        var leftMargin = doc.PageSetup.LeftMargin;
        var rightMargin = doc.PageSetup.RightMargin;
        table.PreferredWidthType = 1; // wdPreferredWidthPercentage
        table.PreferredWidth = pageWidth - leftMargin - rightMargin;

        if (table.Rows.Count > 1) {
            table.AllowAutoFit = true;
            try {
                table.Rows.First.AllowBreakAcrossPages = false;
            } catch(e) {}
        }
    } catch (e) {}
}

// 3. 公式处理：遍历段落，根据内容判断是否为公式或公式编号
var paras = doc.Paragraphs;
for (var k = 0; k < paras.Count; k++) {
    var para = paras.Item(k);
    var text = para.Range.Text.replace(/\r\n/g, '').trim();

    // 公式编号段：以"("开头或以")"结尾
    if (text.indexOf("(") === 0 || text.lastIndexOf(")") === text.length - 1) {
        try {
            para.Range.ParagraphFormat.Alignment = 2; // 右对齐
        } catch (e) {}
    } 
    // 纯公式段：包含数学符号但无编号括号
    else if (text.match(/[\u2200-\u22FF\u03B1-\u03C9=\+\-\*\/]/) && !text.includes("(")) {
        try {
            para.Range.ParagraphFormat.Alignment = 1; // 居中
        } catch (e) {}
    }
}

return {
    success: true,
    message: "图片已居中，表格已设为等宽并启用跨页重复表头，公式及编号已按规则对齐。"
};

